class SAMLResponseParser:
    """Parses and validates SAML responses from the Identity Provider."""

    def __init__(self, saml_response_b64):
        self.raw_response = base64.b64decode(saml_response_b64)
        self.xml_string = self.raw_response.decode('utf-8')
        self.root = ET.fromstring(self.xml_string)
        self.errors = []
        self.attributes = {}
        self.name_id = None
        self.session_index = None
        self.issuer = None
        self.assertion = None

    def validate_response(self):
        """Validate the SAML response structure and status."""
        # Check response status
        status_code_elem = self.root.find(
            './/samlp:Status/samlp:StatusCode',
            SAML_NAMESPACES
        )
        if status_code_elem is None:
            self.errors.append('No StatusCode element found in SAML response.')
            return False

        status_value = status_code_elem.get('Value', '')
        if status_value != 'urn:oasis:names:tc:SAML:2.0:status:Success':
            status_message_elem = self.root.find(
                './/samlp:Status/samlp:StatusMessage',
                SAML_NAMESPACES
            )
            message = status_message_elem.text if status_message_elem is not None else 'Unknown error'
            self.errors.append(f'SAML response status is not Success: {status_value}. Message: {message}')
            return False

        # Validate destination
        destination = self.root.get('Destination', '')
        if destination and destination != SAML_CONFIG['sp_acs_url']:
            self.errors.append(
                f'Response Destination mismatch. Expected: {SAML_CONFIG["sp_acs_url"]}, Got: {destination}'
            )
            return False

        # Validate issuer at response level
        response_issuer = self.root.find('saml:Issuer', SAML_NAMESPACES)
        if response_issuer is not None:
            if response_issuer.text != SAML_CONFIG['idp_entity_id']:
                self.errors.append(
                    f'Response Issuer mismatch. Expected: {SAML_CONFIG["idp_entity_id"]}, Got: {response_issuer.text}'
                )
                return False

        return True

    def validate_assertion(self):
        """Validate that an assertion is present and structurally valid."""
        self.assertion = self.root.find('saml:Assertion', SAML_NAMESPACES)
        if self.assertion is None:
            # Try to find encrypted assertion
            encrypted_assertion = self.root.find('saml:EncryptedAssertion', SAML_NAMESPACES)
            if encrypted_assertion is not None:
                self.errors.append(
                    'EncryptedAssertion found but decryption is not supported in this implementation. '
                    'Configure IdP to send unencrypted assertions or implement decryption.'
                )
            else:
                self.errors.append('No Assertion element found in SAML response.')
            return False

        # Validate assertion issuer
        assertion_issuer = self.assertion.find('saml:Issuer', SAML_NAMESPACES)
        if assertion_issuer is None:
            self.errors.append('No Issuer found in Assertion.')
            return False

        self.issuer = assertion_issuer.text
        if self.issuer != SAML_CONFIG['idp_entity_id']:
            self.errors.append(
                f'Assertion Issuer mismatch. Expected: {SAML_CONFIG["idp_entity_id"]}, Got: {self.issuer}'
            )
            return False

        return True

    def validate_conditions(self):
        """Validate assertion conditions (time-based and audience)."""
        if self.assertion is None:
            return False

        conditions = self.assertion.find('saml:Conditions', SAML_NAMESPACES)
        if conditions is None:
            # Conditions are optional but recommended
            return True

        now = datetime.utcnow()

        # Check NotBefore
        not_before = conditions.get('NotBefore')
        if not_before:
            not_before_dt = self._parse_saml_datetime(not_before)
            if not_before_dt and now < not_before_dt - timedelta(minutes=5):  # 5 min clock skew tolerance
                self.errors.append(
                    f'Assertion is not yet valid. NotBefore: {not_before}, Current time: {now.isoformat()}'
                )
                return False

        # Check NotOnOrAfter
        not_on_or_after = conditions.get('NotOnOrAfter')
        if not_on_or_after:
            not_on_or_after_dt = self._parse_saml_datetime(not_on_or_after)
            if not_on_or_after_dt and now >= not_on_or_after_dt + timedelta(minutes=5):  # 5 min clock skew tolerance
                self.errors.append(
                    f'Assertion has expired. NotOnOrAfter: {not_on_or_after}, Current time: {now.isoformat()}'
                )
                return False

        # Check AudienceRestriction
        audience_restriction = conditions.find(
            'saml:AudienceRestriction', SAML_NAMESPACES
        )
        if audience_restriction is not None:
            audiences = audience_restriction.findall('saml:Audience', SAML_NAMESPACES)
            audience_values = [a.text for a in audiences if a.text]
            if audience_values and SAML_CONFIG['sp_entity_id'] not in audience_values:
                self.errors.append(
                    f'SP entity ID not in audience list. Expected: {SAML_CONFIG["sp_entity_id"]}, '
                    f'Got: {audience_values}'
                )
                return False

        return True

    def validate_subject_confirmation(self):
        """Validate SubjectConfirmation data."""
        if self.assertion is None:
            return False

        subject = self.assertion.find('saml:Subject', SAML_NAMESPACES)
        if subject is None:
            self.errors.append('No Subject element found in Assertion.')
            return False

        subject_confirmation = subject.find('saml:SubjectConfirmation', SAML_NAMESPACES)
        if subject_confirmation is not None:
            method = subject_confirmation.get('Method', '')
            if method != 'urn:oasis:names:tc:SAML:2.0:cm:bearer':
                self.errors.append(f'Unsupported SubjectConfirmation Method: {method}')
                return False

            confirmation_data = subject_confirmation.find(
                'saml:SubjectConfirmationData', SAML_NAMESPACES
            )
            if confirmation_data is not None:
                # Validate Recipient
                recipient = confirmation_data.get('Recipient', '')
                if recipient and recipient != SAML_CONFIG['sp_acs_url']:
                    self.errors.append(
                        f'SubjectConfirmationData Recipient mismatch. '
                        f'Expected: {SAML_CONFIG["sp_acs_url"]}, Got: {recipient}'
                    )
                    return False

                # Validate NotOnOrAfter
                not_on_or_after = confirmation_data.get('NotOnOrAfter')
                if not_on_or_after:
                    not_on_or_after_dt = self._parse_saml_datetime(not_on_or_after)
                    now = datetime.utcnow()
                    if not_on_or_after_dt and now >= not_on_or_after_dt + timedelta(minutes=5):
                        self.errors.append(
                            f'SubjectConfirmationData has expired. NotOnOrAfter: {not_on_or_after}'
                        )
                        return False

        return True

    def extract_name_id(self):
        """Extract the NameID from the assertion Subject."""
        if self.assertion is None:
            return None

        subject = self.assertion.find('saml:Subject', SAML_NAMESPACES)
        if subject is None:
            return None

        name_id_elem = subject.find('saml:NameID', SAML_NAMESPACES)
        if name_id_elem is not None and name_id_elem.text:
            self.name_id = name_id_elem.text.strip()
            return self.name_id

        return None

    def extract_session_index(self):
        """Extract the SessionIndex from AuthnStatement."""
        if self.assertion is None:
            return None

        authn_statement = self.assertion.find('saml:AuthnStatement', SAML_NAMESPACES)
        if authn_statement is not None:
            self.session_index = authn_statement.get('SessionIndex')
            return self.session_index

        return None

    def extract_attributes(self):
        """Extract user attributes from the assertion's AttributeStatement."""
        if self.assertion is None:
            return {}

        attribute_statement = self.assertion.find(
            'saml:AttributeStatement', SAML_NAMESPACES
        )
        if attribute_statement is None:
            return {}

        attributes = {}
        for attribute in attribute_statement.findall('saml:Attribute', SAML_NAMESPACES):
            attr_name = attribute.get('Name', '')
            friendly_name = attribute.get('FriendlyName', '')

            values = []
            for attr_value in attribute.findall('saml:AttributeValue', SAML_NAMESPACES):
                if attr_value.text:
                    values.append(attr_value.text.strip())

            # Use friendly name as key if available, otherwise use full name
            key = friendly_name if friendly_name else attr_name

            # Store single values as strings, multiple as lists
            if len(values) == 1:
                attributes[key] = values[0]
            elif len(values) > 1:
                attributes[key] = values
            else:
                attributes[key] = None

            # Also store by full attribute name for lookup
            if friendly_name and attr_name:
                attributes[attr_name] = attributes[key]

        self.attributes = attributes
        return attributes

    def parse_and_validate(self):
        """Full parsing and validation pipeline."""
        results = {
            'valid': False,
            'errors': [],
            'name_id': None,
            'session_index': None,
            'attributes': {},
            'issuer': None,
        }

        # Step 1: Validate response status
        if not self.validate_response():
            results['errors'] = self.errors
            return results

        # Step 2: Validate assertion presence
        if not self.validate_assertion():
            results['errors'] = self.errors
            return results

        # Step 3: Validate conditions
        if not self.validate_conditions():
            results['errors'] = self.errors
            return results

        # Step 4: Validate subject confirmation
        if not self.validate_subject_confirmation():
            results['errors'] = self.errors
            return results

        # Step 5: Extract data
        self.extract_name_id()
        self.extract_session_index()
        self.extract_attributes()

        if not self.name_id:
            self.errors.append('No NameID found in assertion Subject.')
            results['errors'] = self.errors
            return results

        results['valid'] = True
        results['name_id'] = self.name_id
        results['session_index'] = self.session_index
        results['attributes'] = self.attributes
        results['issuer'] = self.issuer
        results['errors'] = self.errors

        return results

    @staticmethod
    def _parse_saml_datetime(dt_string):
        """Parse SAML datetime string to Python datetime."""
        try:
            # Handle format: 2024-01-15T10:30:00Z
            if dt_string.endswith('Z'):
                dt_string = dt_string[:-1]
            return datetime.fromisoformat(dt_string)
        except (ValueError, TypeError):
            return None


def create_authn_request():
    """Create a SAML AuthnRequest XML."""
    request_id = f'_id-{uuid.uuid4().hex}'
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')

    authn_request = f'''<samlp:AuthnRequest
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{request_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{SAML_CONFIG['idp_sso_url']}"
    AssertionConsumerServiceURL="{SAML_CONFIG['sp_acs_url']}"
    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
    <saml:Issuer>{SAML_CONFIG['sp_entity_id']}</saml:Issuer>
    <samlp:NameIDPolicy
        Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
        AllowCreate="true"/>
</samlp:AuthnRequest>'''

    return request_id, authn_request


